<?php
namespace Tests\Feature\Repayments;
use App\Domain\Repayments\Actions\ApplyLatePenalties;use App\Domain\Repayments\Actions\RefreshLoanArrears;use App\Enums\LoanApplicationStatus;use App\Enums\LoanStatus;use App\Models\ApprovalWorkflow;use App\Models\Charge;use App\Models\Cooperative;use App\Models\Loan;use App\Models\LoanApplication;use App\Models\LoanProduct;use App\Models\Member;use App\Support\Tenancy\TenantContext;use Illuminate\Foundation\Testing\RefreshDatabase;use Tests\TestCase;
class ArrearsPenaltyTest extends TestCase{use RefreshDatabase;public function test_overdue_installment_receives_configured_penalty_once():void{$cooperative=Cooperative::factory()->create();app(TenantContext::class)->set($cooperative);$member=Member::factory()->create(['cooperative_id'=>$cooperative->id]);$workflow=ApprovalWorkflow::query()->create(['name'=>'Approval','code'=>'APP','entity_type'=>'loan_application','is_active'=>true]);$product=LoanProduct::factory()->create(['cooperative_id'=>$cooperative->id,'approval_workflow_id'=>$workflow->id,'configuration'=>['recovery_escalation_days'=>30]]);$charge=Charge::factory()->create(['cooperative_id'=>$cooperative->id,'application_timing'=>'late_repayment','calculation_type'=>'fixed','fixed_amount_minor'=>2500,'rate_basis_points'=>null,'configuration'=>['recurrence'=>'one_time']]);$product->charges()->attach($charge,['sequence'=>1,'is_mandatory'=>true]);$application=LoanApplication::query()->create(['member_id'=>$member->id,'loan_product_id'=>$product->id,'reference'=>'LAP-LATE','requested_principal_minor'=>100000,'tenure'=>1,'purpose'=>'Test','status'=>LoanApplicationStatus::Disbursed,'applicant_snapshot'=>[]]);$loan=Loan::query()->create(['loan_application_id'=>$application->id,'member_id'=>$member->id,'loan_product_id'=>$product->id,'loan_number'=>'LN-LATE','principal_minor'=>100000,'interest_minor'=>0,'repayable_minor'=>100000,'outstanding_minor'=>100000,'status'=>LoanStatus::Active,'disbursed_at'=>today()->subMonths(2),'maturity_date'=>today()->subDay()]);$installment=$loan->installments()->create(['installment_number'=>1,'due_date'=>today()->subDay(),'principal_due_minor'=>100000,'interest_due_minor'=>0,'charges_due_minor'=>0,'status'=>'due']);app(RefreshLoanArrears::class)->execute();$action=app(ApplyLatePenalties::class);$action->execute();$action->execute();$this->assertSame(2500,$installment->refresh()->penalties_due_minor);$this->assertDatabaseCount('loan_penalty_applications',1);}}
